import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const o=JSON.parse('{"title":"鍵令一覧","description":"","frontmatter":{},"headers":[],"relativePath":"ja/key-orders/list.md","filePath":"ja/key-orders/list.md","lastUpdated":1775394001000}'),n={name:"ja/key-orders/list.md"};function s(i,t,r,g,y,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="鍵令一覧" tabindex="-1">鍵令一覧 <a class="header-anchor" href="#鍵令一覧" aria-label="Permalink to &quot;鍵令一覧&quot;">​</a></h1><p>銀鍵システムに関連する鍵令（Key Orders）の一覧です。銀鍵エネルギーが1000に達すると発動可能で、1ターンに1回使用できます（純混沌編成時は2回）。</p><h2 id="汎用鍵令" tabindex="-1">汎用鍵令 <a class="header-anchor" href="#汎用鍵令" aria-label="Permalink to &quot;汎用鍵令&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">鍵令名</th><th style="text-align:center;">界域親和</th><th style="text-align:left;">効果</th><th style="text-align:left;">入手方法</th></tr></thead><tbody><tr><td style="text-align:left;">鼠辈智慧 (Mouse Wisdom)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">算力を3点獲得</td><td style="text-align:left;">メインステージ2-15通関</td></tr><tr><td style="text-align:left;">小小心愿 (Little Wish)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">覚醒体1名を選び、35点の狂気を付与</td><td style="text-align:left;">メインストーリー</td></tr><tr><td style="text-align:left;">酒馆之门 (The Tavern Door)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">「莉雅の硬貨」（算力2点獲得+2枚ドロー）を1枚捨札に追加</td><td style="text-align:left;">多維連動「逆流...」通関</td></tr><tr><td style="text-align:left;">注射防卫 (Injection Guard)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">防御/シールド関連効果（詳細未確認）</td><td style="text-align:left;">メインストーリー</td></tr><tr><td style="text-align:left;">永世执念 (Eternal Obsession)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">臨時会心率25%+臨時力量7点獲得。ボス戦で当ターン未プレイなら死亡抵抗1回発動、成功時シールド138点獲得（1回限り）</td><td style="text-align:left;">メインストーリー</td></tr><tr><td style="text-align:left;">不平等交换 (Unequal Exchange)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">正面効果（詳細未確認）。v1.1で「次ターンドロー-1」の副作用が撤廃</td><td style="text-align:left;">メインストーリー</td></tr><tr><td style="text-align:left;">仲夏之梦 (A Momentary Dream)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">1枚ドロー。指令カードまたは霊知覚醒なら算力消費0に変更、それ以外は捨てて効果を繰り返す。本戦闘中の界域精通を永続25点上昇</td><td style="text-align:left;">メインストーリー</td></tr><tr><td style="text-align:left;">最后的誓言 (The Final Oath)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">臨時力量23点+臨時会心率25%獲得。ボス戦で当ターン未プレイなら死亡抵抗1回発動、成功時バリア1層獲得（1回限り）</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">回溯的终末 (Retrospective End)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">前ターンに最後にプレイした非派生指令カードの原本コピーを手札に追加（算力消費-1、消耗+虚無付き）</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">不朽的葬仪 (Immortal Funeral Rites)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">全覚醒体に12点の狂気を付与。次ターン開始時に最大HP5%の献祭を受ける</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">岁末花火 (Year-End Fireworks)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">味方1名の臨時強効+1、その味方の異なるスキル2枚を獲得。ターン終了時に全手札を捨てる</td><td style="text-align:left;">v1.1.11アップデート</td></tr><tr><td style="text-align:left;">深宅往事 (Manor Memories)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">味方1名を選択、他の味方と全敵に「痴醉」1層付与（指令カード・狂気爆発のダメージ/回復/シールド効果-10%、駆散不可、上限2層）</td><td style="text-align:left;">ストーリー解放</td></tr><tr><td style="text-align:left;">泣血的圣心 (Bleeding Sacred Heart)</td><td style="text-align:center;">汎用</td><td style="text-align:left;">算力消費が最も高い「スキル」を1枚ドローし、予備状態を付与</td><td style="text-align:left;">ストーリー/イベント解放</td></tr></tbody></table><h2 id="界域特化鍵令" tabindex="-1">界域特化鍵令 <a class="header-anchor" href="#界域特化鍵令" aria-label="Permalink to &quot;界域特化鍵令&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">鍵令名</th><th style="text-align:center;">界域親和</th><th style="text-align:left;">効果</th><th style="text-align:left;">界域ボーナス</th><th style="text-align:left;">入手方法</th></tr></thead><tbody><tr><td style="text-align:left;">咆哮的血与沙 (Roar of Blood and Sand)</td><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">現在HPの10%を失い、覚醒体1名に25点の狂気と12点の力量を付与</td><td style="text-align:left;">血肉界域：追加で胚胎融合度+25</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">蚀骨的拥抱 (Corrosive Embrace)</td><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">算力1点獲得、次ターン開始時にシールド75点獲得</td><td style="text-align:left;">深海界域：シールドの代わりに触腕1体を生成</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">短暂的永恒 (Brief Eternity)</td><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">覚醒体1名を選び、その「打撃」と「防御」各2枚を手札に追加（消耗+虚無付き）</td><td style="text-align:left;">超維界域：追加で臨時力量15点+臨時警戒4点獲得</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">灰雾面容 (Ashen Mist Visage)</td><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">本戦闘中の会心率を永続5%上昇、「霊感」1枚を手札に追加</td><td style="text-align:left;">超維界域（超維ターン中）：追加で「霊感」1枚を手札に追加</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">湖畔回眸 (Lakeside Glance)</td><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">シールド60点獲得、全敵に味方シールドの25%相当の中毒を付与</td><td style="text-align:left;">血肉界域：HP損失が多いほど中毒量増加（最大シールド値の50%）</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">玫瑰的胜利 (Victory of the Rose)</td><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">HP45点回復。HP25%以下の場合、回復量と同等の臨時力量を獲得</td><td style="text-align:left;">血肉界域：回復量+50%、直接回復せず猩紅溶鉱炉に蓄積</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr><tr><td style="text-align:left;">奥瑞塔的宝藏 (Aurita&#39;s Treasure)</td><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">抽札堆から算力が最も低い3枚を手札に追加</td><td style="text-align:left;">深海界域：追加で触腕ダメージ+4~8点</td><td style="text-align:left;">拡張計画/ストーリー解放</td></tr></tbody></table><h2 id="チーム別おすすめ鍵令" tabindex="-1">チーム別おすすめ鍵令 <a class="header-anchor" href="#チーム別おすすめ鍵令" aria-label="Permalink to &quot;チーム別おすすめ鍵令&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">チームタイプ</th><th style="text-align:left;">おすすめ鍵令</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:left;">深海触腕チーム</td><td style="text-align:left;">奥瑞塔的宝藏、蚀骨的拥抱</td><td style="text-align:left;">触腕生成と触腕ダメージ強化</td></tr><tr><td style="text-align:left;">血肉胚胎/融合チーム</td><td style="text-align:left;">咆哮的血与沙、湖畔回眸、玫瑰的胜利</td><td style="text-align:left;">胚胎融合度・HP損失連動・猩紅溶鉱炉蓄積</td></tr><tr><td style="text-align:left;">超維カード回転チーム</td><td style="text-align:left;">短暂的永恒、灰雾面容</td><td style="text-align:left;">追加手札生成・霊感カードで超維ターン支援</td></tr><tr><td style="text-align:left;">力量バーストチーム</td><td style="text-align:left;">永世执念、最后的誓言</td><td style="text-align:left;">大幅な力量バフと会心率上昇</td></tr><tr><td style="text-align:left;">狂気速充チーム</td><td style="text-align:left;">不朽的葬仪、咆哮的血与沙、小小心愿</td><td style="text-align:left;">狂気を素早く充填して狂気爆発を発動</td></tr><tr><td style="text-align:left;">汎用/初心者</td><td style="text-align:left;">仲夏之梦、鼠辈智慧、酒馆之门</td><td style="text-align:left;">算力補充とドローで全チームに対応</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>鍵令の数値は守密人レベル60基準です。純混沌編成では毎ターン自動で銀鍵エネルギー250点が蓄積され、1ターンに2回鍵令を使用できます。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">鍵令概要</a></li><li><a href="./../modes/combat.html">戦闘システム</a></li><li><a href="./../engravings/list.html">刻印一覧</a></li></ul>',11)])])}const c=e(n,[["render",s]]);export{o as __pageData,c as default};
